/** Webpack standalone build (`yarn start:std`). VITE_STANDALONE is injected by webpack DefinePlugin. */
declare const VITE_STANDALONE: string | undefined;

const standaloneFlag: string | undefined = typeof VITE_STANDALONE !== 'undefined' ? VITE_STANDALONE : (import.meta as any).env?.VITE_STANDALONE;
export const isStandalone = standaloneFlag === 'true';

/** Hiện route `/dev` khi dev server hoặc standalone. */
export const showDevNav = (import.meta as any).env?.DEV === true || isStandalone;
